import sys

class Solution:
    def contains_duplicate_triple(self, nums: list[int]) -> bool:
        count = {}
        for i in range(len(nums) - 2):
            if nums[i] == nums[i + 1]:
                if nums[i] not in count:
                    count[nums[i]] = 1
                    for j in range(i + 1, len(nums) - 1):
                        if nums[j] == nums[j + 1]:
                            if nums[j] not in count:
                                count[nums[j]] = 1
                                for k in range(j + 1, len(nums) - 2):
                                    if nums[k] == nums[k + 1] and nums[k] == nums[k + 2]:
                                        return True
                else:
                    return True
        return False

if __name__ == '__main__':
    t = int(sys.stdin.readline())
    for tt in range(t):
        sys.stdin.readline()
        nums = list(map(int, sys.stdin.readline().split()))
        print(Solution().contains_duplicate_triple(nums))

